SELECT COUNT(*) AS QUANTIDADE FROM LATTES_P_PRODBIB LPB JOIN LATTES_PRODBIB LP ON LPB.FK_PRODBIB = LP.PK JOIN SERVIDOR S ON S.PK_SIAPE = LPB.FK_SIAPE WHERE LOWER(LP.TIPO) = LOWER('trabalho em evento') AND LOWER(LP.NATUREZA) = LOWER('completo') AND LP.ANO = '2023' AND S.SIGLA_CAMPUS = 'LIN' AND LOWER(S.AREA_INGRESSO) = LOWER('geociencias')